class Solution {
public:
    long long validSubstringCount(string word1, string word2) {
        int n = word1.size(), m = word2.size();
        if (n < m) return 0;

        int freq2[26] = {0};
        for (char c : word2) freq2[c - 'a']++;

        int freq1[26] = {0};
        int left = 0, unique = 0;
        long long res = 0;

        for (int right = 0; right < n; ++right) {
            int c = word1[right] - 'a';
            if (++freq1[c] == freq2[c]) ++unique;

            while (left <= right && (right - left + 1) >= m) {
                if (unique == 26) break;

                bool ok = true;
                for (int i = 0; i < 26; ++i) {
                    if (freq1[i] < freq2[i]) {
                        ok = false;
                        break;
                    }
                }
                if (ok) break;
                int d = word1[left] - 'a';
                if (freq1[d] == freq2[d]) --unique;
                --freq1[d];
                ++left;
            }

            if (right - left + 1 >= m) {
                bool ok = true;
                for (int i = 0; i < 26; ++i) {
                    if (freq1[i] < freq2[i]) {
                        ok = false;
                        break;
                    }
                }
                if (ok) res += left + 1;
            }
        }
        return res;
    }
};
